import { useState } from "react";
import PropTypes from "prop-types";

const formatCurrency = (value) => `₹ ${value.toLocaleString()}`;

function ListingDetail({ listing, initialSaved = false }) {
  const [saved, setSaved] = useState(initialSaved);

  const toggleSave = () => setSaved(!saved);

  if (!listing) return null;

  return (
    <div style={{ marginTop: 12 }}>
      <h3>{listing.title}</h3>
      <p className={styles.muted}>
        {listing.location} • {listing.guests || 1} guest(s)
      </p>
      <p className={styles.price}>{formatCurrency(listing.price)}</p>
      <button className={styles.button} onClick={toggleSave}>
        {saved ? "Saved" : "Save"}
      </button>
    </div>
  );
}

ListingDetail.propTypes = {
  listing: PropTypes.object.isRequired,
  initialSaved: PropTypes.bool,
};

export default ListingDetail;
